mapper.select:
SELECT p.*, c.name AS category_name, (SELECT COUNT(*) FROM sku WHERE product_id = p.id) AS sku_count, (SELECT MIN(price) FROM sku WHERE product_id = p.id) AS min_price FROM product p LEFT JOIN category c ON p.category_id = c.id
AND p.name LIKE CONCAT('%', #{keyword}, '%')
AND p.category_id = #{categoryId}
AND p.type = #{type}
AND p.status = #{status}
ORDER BY p.sort ASC, p.id DESC
